// [CoreDNA] 애플리케이션 빌더: 원격 설정 파일을 기반으로 완전한 웹 페이지를 구축합니다.\n(async () => {\n  // [VPC] FOUC(Flash of Unstyled Content) 방지를 위해 바디를 초기에 숨깁니다.\n  document.body.style.visibility = 'hidden';\n\n  try {\n    // [CoreDNA] 1. 설정 파일(설계도)을 가져옵니다.\n    const configResponse = await fetch('config/config_v2.json');\n    if (!configResponse.ok) throw new Error(`네트워크 오류: config_v2.json 로드 실패 (상태: ${configResponse.status})`);\n    const config = await configResponse.json();\n\n    // [CoreDNA] 2. 페이지 <head>를 구축합니다.\n    await buildHead(config.meta);\n\n    // [CoreDNA] 3. 페이지 <body>의 기본 구조를 만들고 컨텐츠를 채웁니다.\n    await buildBody(config.templates, config.modules);\n\n    console.log("[bootstrap_v2] 애플리케이션 구축 성공!");\n\n  } catch (error) {\n    // [CoreDNA] 치명적 오류 처리\n    console.error("[bootstrap_v2] 애플리케이션 구축 중 치명적 오류 발생:", error);\n    document.body.innerHTML = '<div style="padding: 20px; font-family: sans-serif; color: red;"><h1>Error</h1><p>Application failed to load. Check the console for details.</p><pre>' + error.message + '</pre></div>';\n  } finally {\n    // [VPC] 모든 작업 완료 후, 성공/실패 여부와 관계없이 바디를 다시 표시합니다.\n    document.body.style.visibility = 'visible';\n  }\n\n  // --- Helper Functions ---\n\n  // [HCA] <head> 구성 요소를 생성하는 헬퍼 함수\n  async function buildHead(meta) {\n    document.title = meta.title || 'Dynamic Page';\n    for (const sheetPath of meta.stylesheets) {\n      const link = document.createElement('link');\n      link.rel = 'stylesheet';\n      link.href = sheetPath;\n      document.head.appendChild(link);\n    }\n  }\n\n  // [HCA] <body> 구성 요소를 생성하고 활성화하는 헬퍼 함수\n  async function buildBody(templates, modules) {\n    // 템플릿 주입을 위한 루트 요소 생성\n    const rootDiv = document.createElement('div');\n    rootDiv.id = 'root';\n    document.body.appendChild(rootDiv);\n\n    // 모든 HTML 템플릿을 병렬로 fetch 하고 주입\n    await Promise.all(templates.map(async (template) => {\n      const response = await fetch(template.path);\n      if (!response.ok) throw new Error(`템플릿 로드 실패: ${template.path}`);\n      const html = await response.text();\n      const target = document.getElementById(template.targetElementId);\n      if (target) {\n        target.innerHTML += html;\n      } else {\n        console.warn(`주입 대상 ID(${template.targetElementId})를 찾을 수 없습니다.`);\n      }\n    }));\n\n    // 모든 기능 모듈 스크립트를 순차적으로 로드하고 실행\n    for (const modulePath of modules) {\n      const script = document.createElement('script');\n      script.src = modulePath;\n      script.defer = true; // DOM 파싱 후 실행 보장\n      document.body.appendChild(script);\n    }\n  }\n})();